{
  "query": "mutation Login($input: LoginInput!) {
  login(input: $input) {
    token
    mustChangePassword
    user {
      id
      username
      displayName
      email
      role
    }
  }
}",
  "variables": {
    "input": {
      "email": "admin@platform.local",
      "password": "ChangeMe123!",
      "remember": true
    }
  }
}

{
  "query": "query Me {
  me {
    id
    username
    displayName
    email
    role
    mustChangePassword
  }
}"
}

{
  "query": "mutation ChangePassword($oldPassword: String!, $newPassword: String!) {\n  changePassword(oldPassword: $oldPassword, newPassword: $newPassword)\n}",
  "variables": {
    "oldPassword": "ChangeMe123!",
    "newPassword": "NewSecurePass456!"
  }
}

{
  "query": "mutation Logout {\n  logout\n}"
