{
  "query": "query DashboardOverview($recentLimit: Int, $noticeLimit: Int) {
  dashboardOverview(recentLimit: $recentLimit, noticeLimit: $noticeLimit) {
    stats {
      totalAgents
      runningAgents
      stoppedAgents
      exceptionAgents
      totalVirtualKeys
      totalGateways
      totalResourcePools
      totalUsers
      monthlyCalls
      monthlyTokens
      monthlyCost
    }
    recentAgents {
      id
      name
      agentName
      status
      createdAt
    }
    notices {
      id
      text
      status
      occurredAt
    }
  }
}",
  "variables": {
    "recentLimit": 5,
    "noticeLimit": 5
  }
}

{
  "query": "query Users($filter: UserFilter, $pagination: Pagination, $sort: UserSort) {
  users(filter: $filter, pagination: $pagination, sort: $sort) {
    nodes {
      id
      username
      displayName
      email
      role { id roleKey name }
      connectionStatus
      lastLoginAt
      enabled
      createdAt
      updatedAt
    }
    totalCount
    pageInfo { page pageSize totalPages }
  }
}",
  "variables": {
    "pagination": {
      "page": 1,
      "pageSize": 20
    },
    "sort": {
      "field": "CREATED_AT",
      "direction": "DESC"
    },
    "filter": {}
  }
}

{
  "query": "query UserExists($username: String, $email: String) {\n  userExists(username: $username, email: $email)\n}",
  "variables": {
    "username": "alice",
    "email": "alice@example.com"
  }
}

{
  "query": "query UsersByRole($roleId: ID!) {\n  users(filter: { roleId: $roleId }) {\n    nodes { id username displayName email role { id roleKey name } connectionStatus lastLoginAt enabled createdAt updatedAt }\n    totalCount\n  }\n}",
  "variables": {
    "roleId": "REPLACE_WITH_ROLE_ID"
  }
}

{
  "query": "mutation CreateUser($input: CreateUserInput!) {
  createUser(input: $input) {
    user {
      id
